var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 그 땅꼬마 녀석. 한번 삐졌다고 사람 무시하기는!","JPN":"ふん、あのチビ。一度気に入らないことがあったからって人を見下して！","ENG":"Hmph, that pipsqueak. I upset her once, and now she's underestimating me!","TWN":"哼，那矮冬瓜，真會記仇！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"강자랑 대련하면 오히려 좋지. 내 랭킹이 팍 오르지 않겠어?","JPN":"強者との戦いは望むところよ。ランキングもぐんと伸びるだろうし！","ENG":"I'd love to fight someone strong. That'll increase my rank higher quickly.","TWN":"和強者對戰反而更好，我的排名不就會暴衝嗎？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"주르! 지금 내 랭크는 몇 위야?","JPN":"J.O.U.R！　今の私のランキングを教えて。","ENG":"J.O.U.R.! What's my rank right now?","TWN":"J.O.U.R.！我現在的排名是多少？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"현재 나이엘 님의 랭크는 목표하신 순위에서 한참을 벗어납니다.","JPN":"現在ナイエル様のランキングは、目標順位より遥かに下です。","ENG":"Your current rank is far from your goal.","TWN":"目前奈爾的排名與目標排名相差甚遠。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"……그래도 정말 들으시겠습니까?","JPN":"……本当に確認しますか？","ENG":"...Would you still like to know?","TWN":"……即便如此，你真的想聽嗎？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"자꾸 기어오를래? 너 진짜 AI 맞아?!","JPN":"生意気ね……あんた本当にAIなの！？","ENG":"What's with that attitude, huh? Are you really an AI?!","TWN":"你在挑釁我嗎？你真的是AI嗎？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"현재 나이엘 님의 랭크는 38위로 집계되었습니다.","JPN":"現在ナイエル様のランキングは38位に確認されました。","ENG":"You are ranked 38th from the top, Miss Naielle.","TWN":"目前奈爾的排名為第38名。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"부족해! 난 최소 한 자릿수가 아니면 안 된다고!","JPN":"足りない！　せめて1桁じゃないとダメなのよ！","ENG":"That's not good enough! It has to be at least a single-digit rank!","TWN":"不行，至少要是個位數才行！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"이번 카운터즈 토너먼트를 포함해, 앞으로 다양한 활약을 보여주신다면, 분명 유의미한 결과를 얻을 수 있을 겁니다.","JPN":"今回のカウンターズ・トーナメントを含め、今後様々な場で活躍を見せてくだされば、有意味な結果を得られるでしょう。","ENG":"If you take part in various events, including the Counters Tournament, I am certain you will achieve meaningful results.","TWN":"包括這次的制裁者淘汰賽在內，如果今後能展現出各種活躍的表現，肯定能取得有意義的結果。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"토너먼트엔 쟁쟁한 태스크포스 출신들이 참가 예정인 건 알고 계시겠죠?","JPN":"トーナメントには錚々たるタスクフォース出身カウンターたちが参加する予定です。","ENG":"Do you know that prominent TASKFORCE members are also participating in the tournament?","TWN":"你知道即將參加淘汰賽的都是一些出類拔萃的特遣勢力成員吧？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"방금 확인된 바에 따르면, 나이엘 님의 1지망이시던 <color=#ffd34c>알파트릭스 이노베이션의 카운터들</color>도 출전이 정해져 있습니다.","JPN":"つい先ほど確認した情報によると、ナイエル様の第1志望である<color=#ffd34c>アルファトリックス・イノベーションのカウンターたち</color>も出場が決まっています。","ENG":"From what I have just confirmed, even Counters from your first-choice TASKFORCE, <color=#ffd34c>Alphatrix Innovation</color>, have signed up.","TWN":"剛剛確認，奈爾第一志願的<color=#ffd34c>阿爾法崔克斯改革的制裁者</color>也確定參賽了。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"정말? 알파트릭스에서도 왔단 말이야?","JPN":"本当？　アルファトリックスからも来てるの？","ENG":"Really? Even from Alphatrix?","TWN":"真的嗎？阿爾法崔克斯的人也來了？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하하, 그럼 그 녀석들을 박살내면 이 몸의 랭킹도 확실히 오르겠지?","JPN":"じゃあ、あいつらをぶっ倒せば、このナイエル様のランキングも確実に上がるってわけね。","ENG":"Haha. My rank should skyrocket if I beat them, no?","TWN":"哈哈，如果把那些傢伙打得落花流水，我的排名肯定會大幅上升吧？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"건투를 빌겠습니다. 부디 좋은 결과 얻으시길.","JPN":"健闘を祈ります。いい結果を得られますように。","ENG":"I wish you good luck and hope you get good results.","TWN":"祝你好運，希望你能取得好結果。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"여러분 안녕하세요. 가은입니다.","JPN":"こんにちは。ユキです。","ENG":"Hello, everyone. This is Gaeun.","TWN":"大家好，我是嘉恩。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"하트베리, 오늘의 컨텐츠는 카운터즈 토너먼트 중계입니다.","JPN":"ハートベリー、今日はカウンターズ・トーナメント中継をお届けします。","ENG":"Today, HRT Berry will be livestreaming Counters Legacy.","TWN":"我是愛心莓果，今天的內容是制裁者淘汰賽直播。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"중계인은 저와 주최자인 가람 씨를 모시겠습니다.","JPN":"解説は私と、主催のカワセ・ヒカリさんでお届けします。","ENG":"The commentators will be me and the organizer of this tournament, Ms. Seo Garam.","TWN":"會由我和主辦單位的嘉蘭小姐一起負責轉播。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"안녕하세요~ 가람입니다.","JPN":"こんにちは～ヒカリです。","ENG":"Hello, I am Garam.","TWN":"大家好～我是嘉蘭。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"가, 가하~? 이, 이렇게 인사하는 게 맞을까요?","JPN":"ヒ、ヒハ～？　あ、挨拶はこんな感じでいいんですか？","ENG":"A-am I doing this right? I-I'm not used to livestreaming.","TWN":"安安？這，這樣打招呼對嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"편하게 해주시면 돼요. 시청자분들은 있는 그대로의 모습을 좋아하니까요.","JPN":"気楽にどうぞ。視聴者はありのままの姿が見たいと思っていますから。","ENG":"You can do it anyway you're comfortable with. Our viewers like to see you for who you are.","TWN":"你就放輕鬆就好。觀眾們喜歡真實的樣子。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"조, 좋아요! 그럼 바로 중계 들어갑니다!","JPN":"わ、わかりました！　では早速中継を始めます！","ENG":"O-okay! Then, let's get straight into the tournament!","TWN":"好，好的！那我馬上開始直播！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"이번 토너먼트는 상위 랭커들은 물론, 유명 태스크포스 출신의 카운터들도 참가가 예정되어 있습니다!","JPN":"今回のトーナメントには、上位ランカーはもちろん、有名タスクフォース出身のカウンターも参加する予定です。","ENG":"This tournament is expected to have not only top rankers participating but also Counters from famous TASKFORCEs!","TWN":"這次淘汰賽不僅有超強選手參加，還有來自著名特遣勢力的制裁者們！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 레거시에서 펼쳐지는 강자들의 혈투! 모두 기대해 주세요!","JPN":"カウンターズ・レガシーで繰り広げられる強者たちの熱い戦い！　ぜひお楽しみください！","ENG":"The battle of the strongest is about to unfold in Counters Legacy! Please stay tuned!","TWN":"這是在制裁者的遺產中展開的強者們的血戰！敬請期待！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그럼 첫 번째 라운드 시작하겠습니다!","JPN":"では第1ラウンドを始めます！","ENG":"Now, the first round has started!","TWN":"那麼，第一輪開始！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"참가자는 랭크 38위이자 카운터 아카데미의 자칭 엘리트! 나이엘 블루스틸!","JPN":"参加者はランキング38位、カウンターアカデミーの自称エリート！　ナイエル・ブルースチール！","ENG":"Our first challenger is rank 38 and is the self-proclaimed elite! Naielle Bluesteel!","TWN":"參賽者是排名第38位，制裁者學院內自稱精英的！奈爾·布魯斯提爾！"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};